INSERT INTO public.reel_analysis (id, reel_id, summary, performance_drivers, retention_factors, content_patterns, lessons_learned, next_ideas, variables_to_repeat, created_at, updated_at) VALUES (1, 30, 'This Reel significantly underperformed compared to the creator''s account averages across all key metrics, including likes, comments, reach, saves, and shares. The content failed to resonate strongly with viewers, likely due to unclear hook, format, or lack of emotional impact.', '{"facts":"The Reel received 78 comments, which is below the account average of 173.2. The shares (1971) and saves (757) were well below the account averages of 21824.38 and 3078.66, respectively.","hypotheses":"The caption, while motivational, may not have been specific or novel enough to drive engagement. The absence of a recorded hook, emotional reaction, and identifiable content type likely hindered its performance."}', '{"facts":"Despite lower engagement, the Reel achieved a reach of 159753, which suggests it may have had moderate interest but lacked sufficient retention or sharing to amplify its reach further.","hypotheses":"Retention might have been impacted by a weak or unrecorded hook and an overly general caption that did not create a strong sense of relatability or urgency to share or save."}', '{"facts":"No clear hook, format, or topic patterns were recorded for this Reel.","hypotheses":"The Reel likely lacked a strong pacing or engaging visual element to maintain attention. Motivational content may need visually striking or personally relatable elements to stand out."}', '{"Develop and record a strong and clear hook that grabs attention within the first few seconds.","Include specific and relatable details within captions or visuals to increase emotional connection.","Test different formats and track which one drives the most engagement, saving, and sharing.","Prioritize recording viewer reactions and feedback to understand what resonates emotionally.","Capitalize on novel or unexpected elements in motivational content to boost shares and saves."}', '{"Create a Reel featuring a personal success story with a strong emotional climax to emphasize opportunity and transformation.","Film a visually captivating, quick-paced Reel with text overlays summarizing major ''one-shot'' success stories from relatable figures or industries.","Collaborate with another creator to discuss pivotal opportunity moments in their life, adding credibility and new viewers.","Use an aspirational soundbite or trending audio that aligns with motivational themes to enhance emotional resonance.","Test a format showcasing real-life viewers'' testimonials or stories reflecting the Reel''s theme to boost relatability."}', '{"Focus on motivational themes but anchor them in specific examples or narratives for relatability.","Monitor and prioritize recording a clear and engaging hook to captivate viewers early.","Incorporate text or audio that emphasizes emotional or transformative moments to drive engagement."}', '2026-04-09 06:31:20.928525+00', '2026-04-09 06:31:20.928525+00');
INSERT INTO public.reel_analysis (id, reel_id, summary, performance_drivers, retention_factors, content_patterns, lessons_learned, next_ideas, variables_to_repeat, created_at, updated_at) VALUES (2, 1, 'This Reel underperformed across all engagement metrics compared to the account''s averages, despite achieving a substantial number of plays. The caption and emotional tone suggest a calming presence, but it may not have resonated deeply enough to drive saves, shares, or comments.', 'The Reel''s plays significantly outpaced the reach, indicating users revisited or watched the content multiple times. However, the likes, comments, saves, and shares fell far below the creator''s average, suggesting weaker emotional resonance or a lack of compelling elements to drive deeper engagement. 
INSERT INTO public.reel_video_analysis (id, reel_id, hook_rating, hook_feedback, pacing, pacing_feedback, audio, audio_feedback, on_screen_text, on_screen_text_feedback, content_type, content_type_feedback, overall_score, suggestions, created_at, updated_at) VALUES (1, 1, 'Strong', 'The first 3 seconds effectively use a text overlay combined with a direct question (''Can I go through ur Instagram?'') and app logos, immediately followed by ''Can I go through ur Chat Gpt?''. This creates an intriguing and slightly uncomfortable premise, instantly hooking the viewer with curiosity about the implied ''cost'' or consequence of such a request. It successfully stops the scroll.', 'Mixed', 'The initial setup with the questions is relatively steady, setting the stage. However, the pacing shifts dramatically and effectively to fast cuts and dynamic action as the video progresses, culminating in the public street performance. This varied pacing keeps the viewer engaged, matching the escalating absurdity of the content.', 'Trending Sound', 'The audio features a dramatic, building instrumental track with spoken elements, which aligns well with the current trends on Instagram Reels. It perfectly complements the visual narrative, adding an epic and slightly melancholic tone to the absurd actions, enhancing the overall emotional impact and engagement.', 'Present', 'The on-screen text (''Can I go through ur Instagram?'' and ''Can I go through ur Chat Gpt?'') is crucial to the hook and the narrative. It''s clear, readable, and perfectly timed to introduce the escalating ''requests.'' It effectively sets up the comedic premise for the visual payoff that follows.', 'Comedy / Trend / POV', 'This Reel masterfully executes a comedic trend based on escalating privacy invasion requests. It transforms an uncomfortable social scenario into a surreal, attention-grabbing street performance, creating a unique and memorable take on the ''what would you do if...'' type of content. The execution is highly effective for audience expectations of comedic short-form video.', '9/10 — Excellent hook and pacing, effectively using a trending audio and text to deliver a unique comedic concept.', '1. Consider adding a quick, subtle reaction shot from the person holding the phone (or being asked) after the ''Chat Gpt'' question to further emphasize the absurdity before the scene transition.
